import React, { useState, useEffect } from 'react';
import SiteCard from '../components/SiteCard';
import { getSites, addSite, updateSite, deleteSite } from '../services/api';

const Sites = () => {
  const [sites, setSites] = useState([]);
  const [loading, setLoading] = useState(true);
  const [showModal, setShowModal] = useState(false);
  const [editSite, setEditSite] = useState(null);
  const [domain, setDomain] = useState('');
  const [name, setName] = useState('');
  const [submitting, setSubmitting] = useState(false);
  const [error, setError] = useState('');
  const [deleteConfirm, setDeleteConfirm] = useState(null);

  const fetchSites = async () => {
    try {
      const res = await getSites();
      setSites(res.data.sites || []);
    } catch (err) {
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => { fetchSites(); }, []);

  const openAddModal = () => {
    setEditSite(null);
    setDomain('');
    setName('');
    setError('');
    setShowModal(true);
  };

  const openEditModal = (site) => {
    setEditSite(site);
    setDomain(site.domain);
    setName(site.name || '');
    setError('');
    setShowModal(true);
  };

  const closeModal = () => {
    setShowModal(false);
    setEditSite(null);
    setDomain('');
    setName('');
    setError('');
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError('');
    setSubmitting(true);
    try {
      if (editSite) {
        const res = await updateSite(editSite.id, { name });
        setSites((prev) => prev.map((s) => (s.id === editSite.id ? res.data.site : s)));
      } else {
        const res = await addSite({ domain, name });
        setSites((prev) => [res.data.site, ...prev]);
      }
      closeModal();
    } catch (err) {
      setError(err.response?.data?.message || 'Operation failed.');
    } finally {
      setSubmitting(false);
    }
  };

  const handleDelete = async (site) => {
    try {
      await deleteSite(site.id);
      setSites((prev) => prev.filter((s) => s.id !== site.id));
      setDeleteConfirm(null);
    } catch (err) {
      console.error(err);
    }
  };

  if (loading) {
    return (
      <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'center', minHeight: '40vh' }}>
        <div className="hm-spinner" style={{ width: '36px', height: '36px', borderWidth: '3px' }}></div>
      </div>
    );
  }

  return (
    <div>
      {/* Header */}
      <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginBottom: '24px' }}>
        <div>
          <h4 style={{ fontWeight: '700', marginBottom: '4px', letterSpacing: '-0.3px' }}>My Sites</h4>
          <p style={{ color: 'var(--text-muted)', fontSize: '14px', margin: 0 }}>
            {sites.length} domain{sites.length !== 1 ? 's' : ''} monitored
          </p>
        </div>
        <button className="btn btn-primary-hm" onClick={openAddModal}>
          <i className="bi bi-plus-lg me-2"></i>Add Site
        </button>
      </div>

      {/* Sites list */}
      {sites.length === 0 ? (
        <div className="empty-state">
          <div className="empty-icon">🌐</div>
          <h5>No sites yet</h5>
          <p>Add your first domain to start monitoring</p>
          <button className="btn btn-primary-hm mt-3" onClick={openAddModal}>
            <i className="bi bi-plus-lg me-2"></i>Add your first site
          </button>
        </div>
      ) : (
        <div style={{ display: 'flex', flexDirection: 'column', gap: '10px' }}>
          {sites.map((site) => (
            <SiteCard
              key={site.id}
              site={site}
              onEdit={openEditModal}
              onDelete={(s) => setDeleteConfirm(s)}
            />
          ))}
        </div>
      )}

      {/* Add/Edit Modal */}
      {showModal && (
        <div className="hm-modal-backdrop" onClick={closeModal}>
          <div className="hm-modal" onClick={(e) => e.stopPropagation()}>
            <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginBottom: '20px' }}>
              <h5 style={{ margin: 0 }}>{editSite ? 'Edit Site' : 'Add New Site'}</h5>
              <button onClick={closeModal} style={{ background: 'none', border: 'none', color: 'var(--text-muted)', cursor: 'pointer', fontSize: '20px' }}>
                <i className="bi bi-x"></i>
              </button>
            </div>

            {error && <div className="hm-alert hm-alert-error mb-3">{error}</div>}

            <form onSubmit={handleSubmit}>
              {!editSite && (
                <div className="mb-3">
                  <label className="hm-label">Domain name</label>
                  <input
                    type="text"
                    className="form-control hm-input"
                    placeholder="e.g. google.com"
                    value={domain}
                    onChange={(e) => setDomain(e.target.value)}
                    required
                    autoFocus
                  />
                  <div style={{ fontSize: '12px', color: 'var(--text-muted)', marginTop: '6px' }}>
                    <i className="bi bi-info-circle me-1"></i>
                    Domain will be validated before adding
                  </div>
                </div>
              )}
              <div className="mb-4">
                <label className="hm-label">Display name <span style={{ color: 'var(--text-muted)' }}>(optional)</span></label>
                <input
                  type="text"
                  className="form-control hm-input"
                  placeholder="My Website"
                  value={name}
                  onChange={(e) => setName(e.target.value)}
                />
              </div>
              <div style={{ display: 'flex', gap: '10px' }}>
                <button type="button" className="btn btn-ghost flex-fill" onClick={closeModal}>
                  Cancel
                </button>
                <button type="submit" className="btn btn-primary-hm flex-fill" disabled={submitting}>
                  {submitting ? (
                    <><span className="hm-spinner me-2"></span>{editSite ? 'Saving...' : 'Validating...'}</>
                  ) : (
                    editSite ? 'Save Changes' : 'Add Site'
                  )}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}

      {/* Delete confirmation modal */}
      {deleteConfirm && (
        <div className="hm-modal-backdrop" onClick={() => setDeleteConfirm(null)}>
          <div className="hm-modal" onClick={(e) => e.stopPropagation()} style={{ maxWidth: '380px' }}>
            <div style={{ textAlign: 'center', padding: '8px 0 20px' }}>
              <div style={{ fontSize: '48px', marginBottom: '16px' }}>🗑️</div>
              <h5>Delete Site</h5>
              <p style={{ color: 'var(--text-secondary)', fontSize: '14px', margin: '8px 0 24px' }}>
                Are you sure you want to remove <strong className="font-mono">{deleteConfirm.domain}</strong>?
                This action cannot be undone.
              </p>
            </div>
            <div style={{ display: 'flex', gap: '10px' }}>
              <button className="btn btn-ghost flex-fill" onClick={() => setDeleteConfirm(null)}>Cancel</button>
              <button className="btn btn-danger-hm flex-fill" onClick={() => handleDelete(deleteConfirm)}
                style={{ padding: '10px !important' }}>
                <i className="bi bi-trash me-1"></i> Delete
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default Sites;
